import{_ as i,a as p,M as t,o}from"./chunks/framework.BzjwFSRk.js";const d=JSON.parse('{"title":"Ангар","description":"Фаблаб","frontmatter":{"title":"Ангар","description":"Фаблаб","date":"2016-12-22","icon":"logo-1.png","address":"ул. Затонская, 44г","place":"Кировский район","city":"г. Красноярск","vk":"fablab24","coord":[55.979357639991065,92.93660427187353],"status":"closed","cover":"XXXL.jpg","youtube":"https://youtu.be/r0vn-Br4Dec"},"headers":[],"relativePath":"workshop/archive/angar/index.md","filePath":"workshop/archive/angar/index.md"}'),r={name:"workshop/archive/angar/index.md"};function a(n,l,s,e,g,u){return o(),p("div",null,[...l[0]||(l[0]=[t('<p><strong>Что такое ФабЛаб «Ангар»?</strong></p><ul><li>это Центр Молодежного Инновационного Творчества, созданный в рамках частно-государственного партнерства по программе МИНЭК, при поддержке и непосредственном участии Министерства инвестиций и инноваций Красноярского края.</li></ul><p><strong>Для кого создан центр?</strong></p><p>Наш ФабЛаб работает для:</p><ul><li>студентов; • молодых специалистов; • участников инновационных сообществ Красноярска; • школьников старших классов; • всех творческих молодых людей, желающих получить навыки работы с высокотехнологичным оборудованием и воплотить свои идеи и проекты в жизнь:)</li></ul><p><strong>Как стать пользователем нашего ФабЛаба?</strong></p><p>Чтобы стать пользователем центра, нужно только желание. Приезжаете к нам, регистрируетесь в журнале посещения и приступаете к работе или изучению технологийJ.</p><p>Кроме непосредственной работы над деталями к проектам в мастерских, у нас можно расположиться за большим столом со своим ноутбуком для проектирования или другой работы. У нас есть вайфай и даже чайник с микроволновкой</p><p><strong>Режим работы ФабЛаба</strong></p><p>Мы открыты для посещения с 10 до 18 в будни. В выходные тоже часто работаем, но лучше заранее сообщать о своем желании посетить нас 😃</p><h2 id="оборудование-fablab-а" tabindex="-1">Оборудование FabLab&#39;а <a class="header-anchor" href="#оборудование-fablab-а" aria-label="Permalink to &quot;Оборудование FabLab&#39;а&quot;">​</a></h2><p>Почти всё оборудование в нашем ФабЛабе с ЧПУ, что позволяет достаточно быстро освоить работу со станками пользователями с любым уровнем начальных знаний и практического опыта, в этом помогают интуитивно понятные интерфейсы и простые, даже для детей, алгоритмы работы.</p><p><strong>Фрезерный станок Flexicam S2 2030</strong></p><p>Описание: Высокоточный и высокоскоростной станок для работы с деревом, пластиками, алюминием и другими материалами.</p><ul><li>вакуумный стол на 8 зон для мгновенной фиксации заготовок;</li><li>может работать без подключения к компьютеру;</li><li>рабочее поле 2040 х 3080 мм;</li><li>система пылеудаления;</li></ul><p>Большой станок для создания больших изделий.</p><p><strong>Лазерный гравер Laser PRO GCC Spirit GX 40</strong></p><p>Описание: Гравировка и резка/раскрой материала шириной до 90 см и любой длины. Обрабатываемые материалы:</p><ul><li>дерево/фанеры/шпон;</li><li>акриловое стекло/оргстекло;</li><li>однослойные и многослойные пластики (кроме ПВХ);</li><li>ПЭТ;</li><li>резина;</li><li>картон/гофрокартон/бумага;</li><li>кожа/кожзам;</li><li>стекло (только гравировка);</li><li>керамика, виниловая пленка, металлы с покрытием и др.</li></ul><p><strong>3D - принтеры BitfromBytes 3D Touch Double HEAD</strong></p><p>Особенности:</p><ul><li>легкий в управлении, имеет сенсорный дисплей;</li><li>может работать без подключения к компьютеру;</li><li>большой размер рабочей области (230 х 275 х 201мм);</li><li>может печатать объект из двух видов пластика (или двух цветов) одновременно;</li><li>высокая точность печати (+/- 0.2мм) - возможна печать в различных цветах.</li></ul><p><strong>3D - принтеры MakerBot Replicator Dual HEAD</strong></p><p>Особенности:</p><ul><li>максимальный объем печатаемых объектов: 5 литров;</li><li>возможна работа без подключения к компьютеру;</li><li>возможна печать в различных цветах;</li><li>может печатать объект из двух видов пластика (или двух цветов) одновременно;</li><li>все параметры печати (температура, толщина слоя и т. д.) могут настраиваться пользователем.</li></ul><p><strong>Лазерный 3D сканер Roland LPX-600DS</strong></p><p>Симпатичный и бесшумный сканер, подключаемый к любому компьютеру через USB. Для работы с ним не требуется никаких профессиональных навыков. Сканирование осуществляется бесконтактным методом двумя способами:</p><ul><li>модель сканируется в 20 различных плоскостях;</li><li>объект сканируется на вращающемся стол.</li></ul><p>Максимальная область сканирования: Диаметр — 254 мм, высота — 406 мм, разрешение 0,2 мм.</p><p><strong>Гравировально - фрезерный 3D станок Roland MDX-40a</strong></p><p>3D сканер позволяет выполнять оцифровку трехмерных объектов, а поворотная ось их последующую четырехстороннюю и круговую обработку. Это наиболее удобный инструмент для создания прототипов, опытных образцов и готовых изделий из пластика, воска, дерева и т. д.</p><p>Позволяет выполнять гравировку штампов, клише, небольших литьевых и пресс-форм на материалах: латунь, магний, алюминий, медь и т. д. Макс. размер устанавливаемой заготовки: диаметр 120 мм, длина 270 мм.</p><p><strong>3D комбайн Roland MDX-20</strong></p><p>Совмещает в себе 3D сканер и фрезерную машину. Подходит для многих областей:</p><ul><li>ювелирной промышленности;</li><li>изготовления литьевых форм;</li><li>быстрого прототипирования;</li><li>мелкосерийного производства;</li><li>дизайна портативных изделий;</li><li>производства сувениров и др.</li></ul><p>Поддерживает обработку широкого спектра материалов, включая ювелирный воск, пластик, акрил, дерево и т.д.</p><p><strong>Режущий плоттер Roland GX-300</strong></p><ul><li>Позволяет вырезать текст высотой 1,5 мм.;</li><li>Обеспечивает качественную резку всех видов самоклеящихся пленок, картона, тонких пластиков (до 0,8 мм);</li><li>Максимальная длина резки — 50 м.;</li><li>Ширина рулона от 50 до 915 мм.</li></ul><p><strong>Токарно-винторезный станок Jet GHB-1330</strong></p><p>Станок относится к профессиональному оборудованию начального уровня. Сочетает в себе простоту эксплуатации, высокие показатели в работе и безопасность.</p><p><strong>Ленточнопильный станок Jet MBS-708CS</strong></p><p>Полупрофессиональный станок для аккуратного распила металлических заготовок. Отличительная черта данной модели - гидравлическая система подачи, которая позволяет опускать поворотную рабочую консоль максимально плавно и обеспечивает полный контроль над процессом.</p>',42)])])}const D=i(r,[["render",a]]);export{d as __pageData,D as default};
